parameters.functionCode:
const allowed = ($env['INTAKE_ALLOW_DOMAINS'] || '').split(',').map(s => s.trim()).filter(Boolean);
const from = $input.first().json.from?.value?.[0]?.address || '';
const host = from.split('@')[1] || '';
if (allowed.length && !allowed.includes(host)) throw new Error('sender-domain-not-allowlisted');
const clientSlug = $env['INTAKE_DEFAULT_CLIENT'] || 'lumivara';
return [{ json: { title: $input.first().json.subject || '(no subject)', body: $input.first().json.text || $input.first().json.html || '', replyTo: from, clientSlug } }];
